INSERT INTO `frases` VALUES (8,'2025-12-05','La vida es como un espejo: si le sonríes, te devuelve la sonrisa.'),(9,'2025-12-05','Transforma tus heridas en sabiduría.'),(10,'2025-12-05','Cada día es una nueva oportunidad para mejorar y crecer.'),(11,'2025-12-05','La felicidad no es tenerlo todo, sino amar lo que tienes.'),(12,'2025-12-05','El éxito llega cuando decides dar el primer paso.'),(14,'2025-12-05','Hazlo con pasión o no lo hagas.'),(15,'2025-12-05','El secreto para salir adelante es comenzar.'),(16,'2025-12-05','No tengas miedo de equivocarte, el verdadero error es no intentarlo.'),(17,'2025-12-05','El coraje no es la ausencia de miedo, sino el triunfo sobre él (Nelson Mandela).'),(18,'2025-12-05','Si te caes, levántate y sigue adelante, siempre hay una nueva oportunidad.'),(19,'2025-12-05','Cuando las cosas parezcan desmoronarse, sé fuerte y valiente; la tormenta pasará.'),(20,'2025-12-05','Siempre hay una solución para todo, nunca pierdas la esperanza.'),(21,'2025-12-05','No dejes que tus miedos limiten tu vida, sal de tu zona de confort y atrévete a ser valiente.');
/*!40000 ALTER TABLE `frases` ENABLE KEYS */;
UNLOCK TABLES;

